import{_ as s,c as a,o as n,a as e}from"./app.09261a68.js";const u=JSON.parse('{"title":"Kubernetes常用配置","description":"","frontmatter":{"date":"2022-12-29T00:00:00.000Z","recommend":4},"headers":[{"level":2,"title":"增加节点","slug":"增加节点","link":"#增加节点","children":[{"level":3,"title":"增加Worker节点","slug":"增加worker节点","link":"#增加worker节点","children":[]},{"level":3,"title":"增加Master节点","slug":"增加master节点","link":"#增加master节点","children":[]}]},{"level":2,"title":"移除节点","slug":"移除节点","link":"#移除节点","children":[]},{"level":2,"title":"设置节点角色","slug":"设置节点角色","link":"#设置节点角色","children":[]},{"level":2,"title":"设置污点","slug":"设置污点","link":"#设置污点","children":[]},{"level":2,"title":"移除污点","slug":"移除污点","link":"#移除污点","children":[]},{"level":2,"title":"配置Kubeconfig","slug":"配置kubeconfig","link":"#配置kubeconfig","children":[]},{"level":2,"title":"更改Kubelet工作路径","slug":"更改kubelet工作路径","link":"#更改kubelet工作路径","children":[]}],"relativePath":"zh/cloud-native/kubernetes/configuration.md"}'),l={name:"zh/cloud-native/kubernetes/configuration.md"},o=e(`<h1 id="kubernetes常用配置" tabindex="-1">Kubernetes常用配置 <a class="header-anchor" href="#kubernetes常用配置" aria-hidden="true">#</a></h1><h2 id="增加节点" tabindex="-1">增加节点 <a class="header-anchor" href="#增加节点" aria-hidden="true">#</a></h2><p>创建集群时控制台打印信息中含有新增节点的指令，可按照该指令增加节点至集群。</p><p>若遗失该指令，或<code>token</code>/<code>certificate-key</code>等参数过期，可参考如下方式重新生成指令：</p><ul><li><a href="#%E5%A2%9E%E5%8A%A0worker%E8%8A%82%E7%82%B9">增加Worker节点</a></li><li><a href="#%E5%A2%9E%E5%8A%A0master%E8%8A%82%E7%82%B9">增加Master节点</a></li></ul><h3 id="增加worker节点" tabindex="-1">增加Worker节点 <a class="header-anchor" href="#增加worker节点" aria-hidden="true">#</a></h3><p>在集群中任意Master节点通过以下命令生成join命令：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">kubeadm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">token</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">create</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--print-join-command</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 控制台打印信息如下：</span></span>
<span class="line"><span style="color:#FFCB6B;">kubeadm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">join</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">kubernetes-vip:</span><span style="color:#F78C6C;">9443</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--token</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">grv9o6.75venx9x7sajjowp</span><span style="color:#A6ACCD;"> \\</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C3E88D;">--discovery-token-ca-cert-hash</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sha256:ea92e650eed7e5df76ab99ac545f61713d3f1ff9001a3281a1f5c71ece7309a5</span></span>
<span class="line"></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>如果<code>token</code>过期，join命令需要重新生成。</p></div><h3 id="增加master节点" tabindex="-1">增加Master节点 <a class="header-anchor" href="#增加master节点" aria-hidden="true">#</a></h3><ul><li><strong>步骤一</strong></li></ul><p>先按照<a href="#%E5%A2%9E%E5%8A%A0worker%E8%8A%82%E7%82%B9">增加Worker节点</a>的操作生成join命令。</p><ul><li><strong>步骤二</strong></li></ul><p>在集群中任意Master节点执行以下节点生成<code>certificate-key</code>:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">kubeadm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">init</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">phase</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">upload-certs</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--upload-certs</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 控制台输出如下：</span></span>
<span class="line"><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">upload-certs</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;"> Storing the certificates </span><span style="color:#89DDFF;font-style:italic;">in</span><span style="color:#A6ACCD;"> Secret</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#C3E88D;">kubeadm-certs</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;font-style:italic;">in</span><span style="color:#A6ACCD;"> the</span><span style="color:#89DDFF;"> &quot;</span><span style="color:#C3E88D;">kube-system</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;"> Namespace</span></span>
<span class="line"><span style="color:#89DDFF;">[</span><span style="color:#A6ACCD;">upload-certs</span><span style="color:#89DDFF;">]</span><span style="color:#A6ACCD;"> Using certificate key:</span></span>
<span class="line"><span style="color:#A6ACCD;">1e610197e25fbb02e695db6124f21874ff865044cd17b2a3fe5ca73b0d8a791c</span></span>
<span class="line"></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>certificate-key</code>有效期为2h, 如果超过了2h, 需要重新生成。</p></div><ul><li><strong>步骤三</strong></li></ul><p>使用<code>--control-plane --certificate-key</code>将步骤一和步骤二中获取到的信息拼接：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">kubeadm</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">join</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">kubernetes-vip:</span><span style="color:#F78C6C;">9443</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--token</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">grv9o6.75venx9x7sajjowp</span><span style="color:#A6ACCD;"> \\</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C3E88D;">--discovery-token-ca-cert-hash</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">sha256:ea92e650eed7e5df76ab99ac545f61713d3f1ff9001a3281a1f5c71ece7309a5</span><span style="color:#A6ACCD;"> \\</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#C3E88D;">--control-plane</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--certificate-key</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">1e610197e25fbb02e695db6124f21874ff865044cd17b2a3fe5ca73b0d8a791c</span></span>
<span class="line"></span></code></pre></div><h2 id="移除节点" tabindex="-1">移除节点 <a class="header-anchor" href="#移除节点" aria-hidden="true">#</a></h2><p>可使用如下指令从Kubernetes集群移除节点：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#676E95;font-style:italic;"># 获取集群中的节点</span></span>
<span class="line"><span style="color:#FFCB6B;">kubectl</span><span style="color:#A6ACCD;">  </span><span style="color:#C3E88D;">get</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">nodes</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 移除指定节点</span></span>
<span class="line"><span style="color:#FFCB6B;">kubectl</span><span style="color:#A6ACCD;">  </span><span style="color:#C3E88D;">delete</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">nodes</span><span style="color:#A6ACCD;"> $nodeName</span></span>
<span class="line"></span></code></pre></div><h2 id="设置节点角色" tabindex="-1">设置节点角色 <a class="header-anchor" href="#设置节点角色" aria-hidden="true">#</a></h2><ul><li>将节点角色设置为<code>Master</code>：</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">kubectl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">label</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">nodes</span><span style="color:#A6ACCD;"> $NodeName </span><span style="color:#C3E88D;">node-role.kubernetes.io/master=</span></span>
<span class="line"></span></code></pre></div><ul><li>将节点角色设置为<code>Worker</code>：</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">kubectl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">label</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">nodes</span><span style="color:#A6ACCD;"> $NodeName </span><span style="color:#C3E88D;">node-role.kubernetes.io/node=</span></span>
<span class="line"></span></code></pre></div><h2 id="设置污点" tabindex="-1">设置污点 <a class="header-anchor" href="#设置污点" aria-hidden="true">#</a></h2><p>为<code>Master</code>节点设置污点，从而工作负载<code>Pod</code>不会被调度到该<code>Master</code>节点上：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">kubectl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">taint</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">nodes</span><span style="color:#A6ACCD;"> $NodeName </span><span style="color:#C3E88D;">node-role.kubernetes.io/master=:NoSchedule</span></span>
<span class="line"></span></code></pre></div><h2 id="移除污点" tabindex="-1">移除污点 <a class="header-anchor" href="#移除污点" aria-hidden="true">#</a></h2><p>移除<code>Master</code>节点的污点，从而工作负载<code>Pod</code>允许被调度到该<code>Master</code>节点上：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">kubectl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">taint</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">nodes</span><span style="color:#A6ACCD;"> $NodeName </span><span style="color:#C3E88D;">node-role.kubernetes.io/master-</span></span>
<span class="line"></span></code></pre></div><h2 id="配置kubeconfig" tabindex="-1">配置Kubeconfig <a class="header-anchor" href="#配置kubeconfig" aria-hidden="true">#</a></h2><p>从<code>Master</code>节点的<code>/etc/cloud-native/kubernetes/admin.conf</code>复制到目的节点上的$kubeconfigPath，然后参考以下脚本：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">mkdir</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-p</span><span style="color:#A6ACCD;"> $HOME</span><span style="color:#C3E88D;">/.kube</span></span>
<span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">cp</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">-i</span><span style="color:#A6ACCD;"> $kubeconfigPath $HOME</span><span style="color:#C3E88D;">/.kube/config</span></span>
<span class="line"><span style="color:#FFCB6B;">sudo</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">chown</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">$(</span><span style="color:#FFCB6B;">id</span><span style="color:#C3E88D;"> -u</span><span style="color:#89DDFF;">)</span><span style="color:#C3E88D;">:</span><span style="color:#89DDFF;">$(</span><span style="color:#FFCB6B;">id</span><span style="color:#C3E88D;"> -g</span><span style="color:#89DDFF;">)</span><span style="color:#A6ACCD;"> $HOME</span><span style="color:#C3E88D;">/.kube/config</span></span>
<span class="line"></span></code></pre></div><h2 id="更改kubelet工作路径" tabindex="-1">更改Kubelet工作路径 <a class="header-anchor" href="#更改kubelet工作路径" aria-hidden="true">#</a></h2><p>在Kubernetes环境中，<code>Pod</code>的卷、日志和其他一些信息将存储在节点的<code>Kubelet</code>工作路径中。</p><p>在Kubernetes节点上，默认的<code>Kubelet</code>工作路径是<code>/var/lib/kubelet</code>，如果该路径所在磁盘比较小，则不能运行很多<code>Pod</code>。如果需要将其修改为其他路径(如<code>/home/k8s/kubelet</code>)，则可参照以下步骤：</p><ul><li><strong>步骤一</strong> 编辑<code>kubeadm.conf</code>,将<code>root-dir</code>标志添加到环境中：</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">vim</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">/usr/lib/systemd/system/kubelet.service.d/</span><span style="color:#F78C6C;">10</span><span style="color:#C3E88D;">-kubeadm.conf</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># find the Environment KUBELET_CONFIG_ARGS and add flag --root-dir=/home/k8s/kubelet</span></span>
<span class="line"><span style="color:#A6ACCD;">Environment</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">KUBELET_CONFIG_ARGS=--config=/var/lib/kubelet/config.yaml --root-dir=/home/k8s/kubelet</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"></span></code></pre></div><ul><li><strong>步骤二</strong> 重新加载守护进程</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">systemctl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">daemon-reload</span></span>
<span class="line"><span style="color:#FFCB6B;">重新启动多维数据集</span></span>
<span class="line"></span></code></pre></div><ul><li><strong>步骤三</strong> 重启<code>Kubelet</code></li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">systemctl</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">restart</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">kubelet</span></span>
<span class="line"></span></code></pre></div><ul><li><strong>步骤四</strong> 查看当前<code>Kubelet</code>工作路径</li></ul><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#FFCB6B;">ps</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">aux</span><span style="color:#89DDFF;">|</span><span style="color:#FFCB6B;">grep</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">kubelet</span><span style="color:#89DDFF;">|</span><span style="color:#FFCB6B;">grep</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--</span><span style="color:#A6ACCD;">  </span><span style="color:#C3E88D;">--root-dir</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;"># 控制台打印如下信息，其中--root-dir对应值即为Kubelet的工作目录</span></span>
<span class="line"><span style="color:#FFCB6B;">root</span><span style="color:#A6ACCD;">      </span><span style="color:#F78C6C;">58574</span><span style="color:#A6ACCD;">  </span><span style="color:#F78C6C;">8.2</span><span style="color:#A6ACCD;">  </span><span style="color:#F78C6C;">0.0</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">5980920</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">118788</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">?</span><span style="color:#A6ACCD;">      </span><span style="color:#C3E88D;">Ssl</span><span style="color:#A6ACCD;">  </span><span style="color:#F78C6C;">00</span><span style="color:#C3E88D;">:</span><span style="color:#F78C6C;">03</span><span style="color:#A6ACCD;">   </span><span style="color:#F78C6C;">2</span><span style="color:#C3E88D;">:</span><span style="color:#F78C6C;">29</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">/usr/bin/kubelet</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--bootstrap-kubeconfig=/etc/cloud-native/kubernetes/bootstrap-kubelet.conf</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--kubeconfig=/etc/cloud-native/kubernetes/kubelet.conf</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--config=/var/lib/kubelet/config.yaml</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--root-dir=/home/k8s/kubelet</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--network-plugin=cni</span><span style="color:#A6ACCD;"> </span><span style="color:#C3E88D;">--pod-infra-container-image=registry.cn-hangzhou.aliyuncs.com/google_containers/pause:3.6</span></span>
<span class="line"></span></code></pre></div><p>现在，当前节点的<code>Kubelet</code>工作路径已更改为<code>/home/k8s/kubelet</code>.</p>`,48),p=[o];function t(c,r,i,C,d,y){return n(),a("div",null,p)}const A=s(l,[["render",t]]);export{u as __pageData,A as default};
